import React, { useState, useEffect, useRef } from 'react';
import { Link, useSearchParams, useNavigate } from 'react-router-dom';
import { useCart } from '../context/CartContext';
import { useAuth } from '../context/AuthContext';
import productService from '../services/productService';
import categoryService from '../services/categoryService';

const productsCache = new Map();

const getFilterCacheKey = (filters) => JSON.stringify(filters);
const toPrice = (value) => {
    const parsed = Number(value);
    return Number.isFinite(parsed) ? parsed : 0;
};

export default function Products() {
    const skeletonCards = Array.from({ length: 8 });
    const [searchParams, setSearchParams] = useSearchParams();
    const navigate = useNavigate();
    const { addItem } = useCart();
    const { isAuthenticated } = useAuth();
    const getFiltersFromParams = () => ({
        search: searchParams.get('search') || '',
        category_id: searchParams.get('category_id') || searchParams.get('category') || '',
        brand: searchParams.get('brand') || '',
        price_min: searchParams.get('price_min') || '',
        price_max: searchParams.get('price_max') || '',
        sort_by: searchParams.get('sort_by') || 'created_at',
        sort_order: searchParams.get('sort_order') || 'desc',
    });

    const initialFilters = getFiltersFromParams();
    const initialCache = productsCache.get(getFilterCacheKey(initialFilters));

    const [products, setProducts] = useState(initialCache || []);
    const [categories, setCategories] = useState([]);
    const [loading, setLoading] = useState(!initialCache);
    const [isRefreshing, setIsRefreshing] = useState(false);
    const [error, setError] = useState(null);
    const [cartErrors, setCartErrors] = useState({});
    const [cartNotice, setCartNotice] = useState('');
    const [addingProductId, setAddingProductId] = useState(null);
    const [recentlyAddedProductId, setRecentlyAddedProductId] = useState(null);
    const recentlyAddedTimerRef = useRef<number | null>(null);

    const [filters, setFilters] = useState(initialFilters);

    useEffect(() => {
        const nextFilters = getFiltersFromParams();
        const hasChanges = JSON.stringify(nextFilters) !== JSON.stringify(filters);
        if (hasChanges) {
            setFilters(nextFilters);
        }
    }, [searchParams]);

    useEffect(() => {
        const fetchCategories = async () => {
            try {
                const res = await categoryService.getAll();
                setCategories(Array.isArray(res?.data?.data) ? res.data.data : []);
            } catch (err) {
                console.error('Failed to fetch categories:', err);
            }
        };

        fetchCategories();
    }, []);

    useEffect(() => {
        const fetchProducts = async () => {
            const cacheKey = getFilterCacheKey(filters);
            const cachedProducts = productsCache.get(cacheKey);

            if (cachedProducts) {
                setProducts(cachedProducts);
                setLoading(false);
                setIsRefreshing(false);
                setError(null);
                return;
            }

            try {
                if (products.length === 0) {
                    setLoading(true);
                } else {
                    setIsRefreshing(true);
                }

                const res = await productService.getAll({ ...filters, per_page: 100 });
                const nextProducts = Array.isArray(res?.data?.data?.data) ? res.data.data.data : [];
                setProducts(nextProducts);
                productsCache.set(cacheKey, nextProducts);
                setError(null);
            } catch (err) {
                setError(err?.response?.data?.message || err?.message || 'Failed to load products.');
            } finally {
                setLoading(false);
                setIsRefreshing(false);
            }
        };

        fetchProducts();
    }, [filters]);

    const handleFilterChange = (key, value) => {
        const newFilters = { ...filters, [key]: value };
        setFilters(newFilters);

        const params = new URLSearchParams();
        Object.entries(newFilters).forEach(([k, v]) => {
            if (v) {
                params.set(k, String(v));
            }
        });
        setSearchParams(params);
    };

    const handleAddToCart = (product) => {
        const productId = Number(product?.id || 0);
        if (!productId || addingProductId === productId) {
            return;
        }

        if (!isAuthenticated) {
            navigate('/login');
            return;
        }

        setCartErrors((prev) => ({ ...prev, [productId]: null }));
        setCartNotice('');
        setAddingProductId(productId);

        addItem(productId, 1, {
            id: productId,
            name: product?.name,
            brand: product?.brand,
            price: toPrice(product?.price),
            images: product?.images,
        })
            .then(() => {
                setCartNotice(`${product?.name || 'Product'} added to cart successfully.`);
                setRecentlyAddedProductId(productId);
            })
            .catch((err) => {
                console.error('Add to cart error:', err);
                const errorMessage = err?.response?.data?.message || err?.message || 'Failed to add product to cart';
                setCartErrors((prev) => ({
                    ...prev,
                    [productId]: errorMessage,
                }));
                setRecentlyAddedProductId((current) => (current === productId ? null : current));
            })
            .finally(() => {
                setAddingProductId((current) => (current === productId ? null : current));
                if (recentlyAddedTimerRef.current !== null) {
                    window.clearTimeout(recentlyAddedTimerRef.current);
                }
                recentlyAddedTimerRef.current = window.setTimeout(() => {
                    setRecentlyAddedProductId((current) => (current === productId ? null : current));
                    recentlyAddedTimerRef.current = null;
                }, 1200);
            });
    };

    useEffect(() => {
        if (!cartNotice) {
            return undefined;
        }

        const timer = setTimeout(() => setCartNotice(''), 2200);
        return () => clearTimeout(timer);
    }, [cartNotice]);

    useEffect(() => () => {
        if (recentlyAddedTimerRef.current !== null) {
            window.clearTimeout(recentlyAddedTimerRef.current);
        }
    }, []);

    const resetFilters = () => {
        const resetState = {
            search: '',
            category_id: '',
            brand: '',
            price_min: '',
            price_max: '',
            sort_by: 'created_at',
            sort_order: 'desc',
        };

        setFilters(resetState);
        setSearchParams(new URLSearchParams());
    };

    return (
        <div className="products-page">
            <div className="products-container">
                <aside className="filters-sidebar">
                    <h3>Filters</h3>

                    <div className="filter-group">
                        <label>Search</label>
                        <input
                            type="text"
                            placeholder="Search products..."
                            value={filters.search}
                            onChange={(e) => handleFilterChange('search', e.target.value)}
                        />
                    </div>

                    <div className="filter-group">
                        <label>Category</label>
                        <select
                            value={filters.category_id}
                            onChange={(e) => handleFilterChange('category_id', e.target.value)}
                        >
                            <option value="">All Categories</option>
                            {categories.map((cat) => (
                                <option key={cat.id} value={cat.id}>
                                    {cat.name}
                                </option>
                            ))}
                        </select>
                    </div>

                    <div className="filter-group">
                        <label>Price Range</label>
                        <input
                            type="number"
                            min="0"
                            placeholder="Max"
                            value={filters.price_max}
                            onChange={(e) => handleFilterChange('price_max', e.target.value)}
                        />
                    </div>

                    <div className="filter-group">
                        <label>Sort By</label>
                        <select
                            value={filters.sort_by}
                            onChange={(e) => handleFilterChange('sort_by', e.target.value)}
                        >
                            <option value="created_at">Newest</option>
                            <option value="price">Price</option>
                            <option value="name">Name</option>
                        </select>
                    </div>
                </aside>

                <div className="products-main">
                    <div className="products-count">
                        Found {products.length} products
                        {isRefreshing && <span className="products-refreshing"> Updating...</span>}
                    </div>

                    {cartNotice && <div className="alert alert-success">{cartNotice}</div>}
                    {error && <div className="error-message">{error}</div>}

                    {loading ? (
                        <div className="products-grid products-grid-skeleton" aria-label="Loading products">
                            {skeletonCards.map((_, index) => (
                                <div key={index} className="product-card product-card-skeleton">
                                    <div className="product-image skeleton-block" />
                                    <div className="product-info">
                                        <div className="skeleton-line skeleton-title" />
                                        <div className="skeleton-line skeleton-brand" />
                                        <div className="skeleton-line skeleton-price" />
                                    </div>
                                    <div className="product-actions">
                                        <div className="skeleton-line skeleton-button" />
                                    </div>
                                </div>
                            ))}
                        </div>
                    ) : products.length === 0 ? (
                        <div className="no-products">
                            <p>No products found. Try adjusting your filters.</p>
                            <button className="btn btn-secondary btn-sm" onClick={resetFilters}>
                                Reset Filters
                            </button>
                        </div>
                    ) : (
                        <div className="products-grid">
                            {products.map((product) => {
                                const price = toPrice(product?.price);
                                const stock = Number(product?.stock || 0);

                                return (
                                    <div key={product.id} className="product-card">
                                        <Link to={`/products/${product.id}`} className="product-link">
                                            <div className="product-image">
                                                {product.images?.[0] ? (
                                                    <img src={product.images[0]} alt={product.name} />
                                                ) : (
                                                    <div className="no-image">No Image</div>
                                                )}
                                            </div>
                                            <div className="product-info">
                                                <h3>{product.name}</h3>
                                                <p className="brand">{product.brand}</p>
                                                <p className="price">₱{price.toFixed(2)}</p>
                                            </div>
                                        </Link>

                                        <div className="product-actions">
                                            {cartErrors[product.id] && (
                                                <div style={{ marginBottom: '0.5rem', padding: '0.5rem', backgroundColor: '#fee2e2', border: '1px solid #fca5a5', borderRadius: '0.25rem', color: '#991b1b', fontSize: '0.75rem' }}>
                                                    {cartErrors[product.id]}
                                                </div>
                                            )}
                                            {stock > 0 ? (
                                                <button
                                                    className="btn btn-primary btn-sm"
                                                    onClick={() => handleAddToCart(product)}
                                                    disabled={addingProductId === product.id}
                                                >
                                                    {addingProductId === product.id
                                                        ? 'Adding...'
                                                        : recentlyAddedProductId === product.id
                                                            ? 'Added'
                                                            : 'Add to Cart'}
                                                </button>
                                            ) : (
                                                <button className="btn btn-disabled btn-sm" disabled>
                                                    Out of Stock
                                                </button>
                                            )}
                                        </div>
                                    </div>
                                );
                            })}
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
}